    chrono.dateTime(new LocalDate(2008, 6, 30)).plusWeeks(1);
    chrono.dateTime(new LocalDate(2008, 12, 28)).plusMonths(1);
    chrono.dateTime(new LocalDate(2008, 12, 28)).plusDays(1);
    System.err.printf("%1$4d %2$3d\n", 2008, 9);
    chrono.dateTime(new LocalDate(2008, 9, 30)).plusMonths(1);
    chrono.dateTime(new LocalDate(2008, 9, 30)).plusQuarters(1);
    chrono.dateTime(new LocalDate(2008, 12, 31)).plusMonths(1);
    chrono.dateTime(new LocalDate(2008, 12, 31)).plusYears(1);
    System.err.printf("%1$4d %2$3d\n", 2016, 2);
